import React, { useState, useEffect } from 'react';
import { supabase } from './supabaseClient';
import Auth from './Auth'; // Importando o componente de 

const [admins, setAdmins] = useState([]);
const [novoAdminEmail, setNovoAdminEmail] = useState('');

function App() {
  // === ESTADOS DO SISTEMA ===
  const [view, setView] = useState('home'); // home, criar, detalhes, login
  const [activeTab, setActiveTab] = useState('confrontos'); 
  const [user, setUser] = useState(null); // Estado do Usuário Logado

  // === ESTADOS DE DADOS ===
  const [campeonatos, setCampeonatos] = useState([]);
  const [campeonatoAtivo, setCampeonatoAtivo] = useState(null);
  const [times, setTimes] = useState([]);
  const [partidas, setPartidas] = useState([]);
  
  // === ESTADOS DE FORMULÁRIOS ===
  const [nome, setNome] = useState('');
  const [formato, setFormato] = useState('pontos-corridos');
  const [qtdTimes, setQtdTimes] = useState(16);
  const [nomeTime, setNomeTime] = useState('');
  const [nomeResponsavel, setNomeResponsavel] = useState('');
  const [escudoFile, setEscudoFile] = useState(null); 
  const [uploading, setUploading] = useState(false);

  // === VERIFICAÇÃO DE SESSÃO (LOGIN) ===
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setUser(session?.user ?? null);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user ?? null);
    });

    return () => subscription.unsubscribe();
  }, []);

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setView('home');
  };

  // === FUNÇÕES DE BUSCA (READ) ===
  const carregarCampeonatos = async () => {
    const { data } = await supabase.from('campeonatos').select('*').order('created_at', { ascending: false });
    if (data) setCampeonatos(data);
  };

  useEffect(() => { carregarCampeonatos(); }, []);

  const carregarTimes = async (id) => {
    const { data } = await supabase.from('times').select('*').eq('campeonato_id', id).order('created_at', { ascending: true });
    if (data) setTimes(data);
  };

  const carregarPartidas = async (id) => {
    const { data } = await supabase
      .from('partidas')
      .select(`*, time_casa:time_casa_id(nome, escudo_url), time_fora:time_fora_id(nome, escudo_url)`)
      .eq('campeonato_id', id)
      .order('rodada', { ascending: true });
    if (data) setPartidas(data);
  };

  const abrirDetalhes = (champ) => {
    setCampeonatoAtivo(champ);
    setView('detalhes');
    carregarTimes(champ.id);
    carregarPartidas(champ.id);
  };

  // === FUNÇÕES DE ESCRITA (CREATE/UPDATE/DELETE) ===
  const criarCampeonatoReal = async (e) => {
    e.preventDefault();
    if (!user) return alert("Você precisa estar logado para criar um campeonato.");
    
    // O Supabase já vai salvar o criador_id automaticamente com base no usuário logado
    await supabase.from('campeonatos').insert([{ nome, formato, qtd_times: qtdTimes }]);
    carregarCampeonatos(); 
    setView('home');
  };

  const adicionarTime = async (e) => {
    e.preventDefault();
    if (times.length >= campeonatoAtivo.qtd_times) return alert("Limite atingido!");
    
    setUploading(true);
    let escudoUrl = null;

    if (escudoFile) {
      const fileExt = escudoFile.name.split('.').pop();
      const fileName = `${Math.random()}.${fileExt}`;
      const { error: uploadError } = await supabase.storage.from('escudos').upload(fileName, escudoFile);

      if (!uploadError) {
        const { data: publicUrlData } = supabase.storage.from('escudos').getPublicUrl(fileName);
        escudoUrl = publicUrlData.publicUrl;
      }
    }

    await supabase.from('times').insert([{ 
      campeonato_id: campeonatoAtivo.id, 
      nome: nomeTime, 
      jogador_responsavel: nomeResponsavel,
      escudo_url: escudoUrl 
    }]);

    setNomeTime(''); setNomeResponsavel(''); setEscudoFile(null);
    if(document.getElementById('fileInput')) document.getElementById('fileInput').value = '';
    setUploading(false);
    carregarTimes(campeonatoAtivo.id);
  };

  const removerTime = async (id) => {
    if (window.confirm("Tens a certeza que queres remover este time?")) {
      await supabase.from('times').delete().eq('id', id);
      carregarTimes(campeonatoAtivo.id);
      carregarPartidas(campeonatoAtivo.id); 
    }
  };

  const gerarTabelaJogos = async () => {
    let timesSorteio = [...times];
    if (timesSorteio.length % 2 !== 0) timesSorteio.push({ id: null, nome: 'FOLGA' });
    const totalRodadas = timesSorteio.length - 1;
    const metade = timesSorteio.length / 2;
    const novasPartidas = [];

    for (let rodada = 1; rodada <= totalRodadas; rodada++) {
      for (let i = 0; i < metade; i++) {
        const casa = timesSorteio[i];
        const fora = timesSorteio[timesSorteio.length - 1 - i];
        if (casa.id && fora.id) {
          novasPartidas.push({ campeonato_id: campeonatoAtivo.id, time_casa_id: casa.id, time_fora_id: fora.id, rodada, status: 'agendado' });
        }
      }
      timesSorteio.splice(1, 0, timesSorteio.pop());
    }
    await supabase.from('partidas').insert(novasPartidas);
    carregarPartidas(campeonatoAtivo.id);
  };

  const atualizarPlacar = async (id, gc, gf) => {
    await supabase.from('partidas').update({ gols_casa: gc, gols_fora: gf, status: 'finalizado' }).eq('id', id);
    carregarPartidas(campeonatoAtivo.id);
  };

  const calcularClassificacao = () => {
    const tabela = times.map(time => {
      let stats = { ...time, p: 0, j: 0, v: 0, e: 0, d: 0, gp: 0, gc: 0, sg: 0 };
      partidas.filter(m => m.status === 'finalizado').forEach(m => {
        if (m.time_casa_id === time.id) {
          stats.j++; stats.gp += m.gols_casa; stats.gc += m.gols_fora;
          if (m.gols_casa > m.gols_fora) { stats.v++; stats.p += 3; }
          else if (m.gols_casa === m.gols_fora) { stats.e++; stats.p += 1; }
          else stats.d++;
        } else if (m.time_fora_id === time.id) {
          stats.j++; stats.gp += m.gols_fora; stats.gc += m.gols_casa;
          if (m.gols_fora > m.gols_casa) { stats.v++; stats.p += 3; }
          else if (m.gols_fora === m.gols_casa) { stats.e++; stats.p += 1; }
          else stats.d++;
        }
      });
      stats.sg = stats.gp - stats.gc;
      return stats;
    });
    return tabela.sort((a, b) => b.p - a.p || b.sg - a.sg || b.gp - a.gp);
  };

  // === VARIÁVEL DE SEGURANÇA VISUAL ===
  const isOwner = user && campeonatoAtivo && user.id === campeonatoAtivo.criador_id;

  return (
    <div className="min-h-screen bg-ef-dark text-white font-sans pb-20">
      
      {/* NAVBAR */}
      <nav className="border-b border-gray-800 p-4 flex justify-between items-center bg-ef-card sticky top-0 z-50">
        <h1 className="text-2xl font-bold italic text-ef-green cursor-pointer" onClick={() => setView('home')}>eFOOTBALL CHAMP</h1>
        <div className="flex items-center space-x-4">
          <button onClick={() => setView('home')} className="hover:text-ef-green transition hidden md:block">Campeonatos</button>
          {user ? (
            <div className="flex items-center space-x-4 border-l border-gray-700 pl-4">
              <span className="text-sm text-gray-400 hidden sm:block">{user.email}</span>
              <button onClick={handleLogout} className="text-red-500 hover:text-red-400 text-sm font-bold">Sair</button>
            </div>
          ) : (
            <button onClick={() => setView('login')} className="bg-ef-green text-black px-4 py-2 rounded-full font-bold hover:bg-green-400">Entrar</button>
          )}
        </div>
      </nav>

      <main className="p-8 max-w-7xl mx-auto">
        
        {/* VIEW: LOGIN */}
        {view === 'login' && <Auth onLogin={() => setView('home')} />}

        {/* VIEW: HOME */}
        {view === 'home' && (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {campeonatos.map(c => (
              <div key={c.id} className="bg-ef-card p-6 rounded-2xl border border-gray-800 hover:border-ef-green transition flex flex-col justify-between h-48">
                <div>
                  <h3 className="text-xl font-bold text-ef-green uppercase italic">{c.nome}</h3>
                  <p className="text-gray-400 text-sm mt-2">{c.qtd_times} Times • {c.formato}</p>
                </div>
                <button onClick={() => abrirDetalhes(c)} className="mt-4 w-full py-2 bg-gray-800 text-white font-bold rounded-lg hover:bg-ef-green hover:text-black transition">
                  Acessar Torneio
                </button>
              </div>
            ))}
            
            {/* BOTÃO DE CRIAR (Exige Login) */}
            <div 
              onClick={() => user ? setView('criar') : setView('login')} 
              className="border-2 border-dashed border-gray-800 p-6 rounded-2xl flex flex-col items-center justify-center text-gray-500 cursor-pointer hover:text-ef-green hover:border-ef-green transition h-48"
            >
              <span className="text-4xl mb-2">+</span>
              <p className="font-bold">{user ? 'Criar Campeonato' : 'Faça Login para Criar'}</p>
            </div>
          </div>
        )}

        {/* VIEW: CRIAR CAMPEONATO */}
        {view === 'criar' && user && (
          <div className="max-w-md mx-auto bg-ef-card p-8 rounded-2xl border border-gray-800">
            <h2 className="text-2xl font-bold mb-6 text-ef-green">Novo Campeonato</h2>
            <form onSubmit={criarCampeonatoReal} className="space-y-4">
              <input value={nome} onChange={e => setNome(e.target.value)} placeholder="Nome do Torneio" required className="w-full bg-ef-dark p-3 rounded border border-gray-700 focus:outline-none focus:border-ef-green" />
              <input type="number" value={qtdTimes} onChange={e => setQtdTimes(e.target.value)} placeholder="Qtd Times" required min="2" max="64" className="w-full bg-ef-dark p-3 rounded border border-gray-700 focus:outline-none focus:border-ef-green" />
              <button className="w-full py-3 bg-ef-green text-black font-bold rounded-lg hover:bg-green-400 transition">Criar e Salvar</button>
            </form>
          </div>
        )}

        {/* VIEW: DETALHES DO CAMPEONATO */}
        {view === 'detalhes' && campeonatoAtivo && (
          <div>
            <header className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4 border-b border-gray-800 pb-6">
              <div>
                <button onClick={() => setView('home')} className="text-gray-500 hover:text-white mb-2 text-sm">← Voltar</button>
                <h2 className="text-4xl font-black text-ef-green italic uppercase">{campeonatoAtivo.nome}</h2>
                {!isOwner && <p className="text-orange-400 text-sm mt-1">Modo Visitante: Apenas Visualização</p>}
              </div>
              
              {/* Só o Dono pode gerar a tabela */}
              {isOwner && partidas.length === 0 && times.length > 1 && (
                <button onClick={gerarTabelaJogos} className="bg-ef-green text-black px-6 py-3 rounded-full font-bold animate-pulse">GERAR TABELA DE JOGOS</button>
              )}
            </header>

            <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
              
              {/* SIDEBAR: TIMES */}
              <div className="lg:col-span-1 space-y-6">
                
                {/* Só o Dono pode adicionar times */}
                {isOwner && partidas.length === 0 && (
                  <div className="bg-ef-card p-5 rounded-xl border border-gray-800">
                    <h4 className="font-bold mb-4">Adicionar Time</h4>
                    <form onSubmit={adicionarTime} className="space-y-3">
                      <input required value={nomeTime} onChange={e => setNomeTime(e.target.value)} placeholder="Nome do Time" className="w-full bg-ef-dark p-2 rounded border border-gray-700 text-sm" />
                      <input required value={nomeResponsavel} onChange={e => setNomeResponsavel(e.target.value)} placeholder="Jogador Responsável" className="w-full bg-ef-dark p-2 rounded border border-gray-700 text-sm" />
                      <div>
                        <label className="block text-xs text-gray-500 mb-1">Escudo (Opcional)</label>
                        <input id="fileInput" type="file" accept="image/*" onChange={e => setEscudoFile(e.target.files[0])} className="w-full text-xs text-gray-400 file:mr-2 file:py-1 file:px-3 file:rounded-full file:border-0 file:bg-gray-800 file:text-ef-green cursor-pointer" />
                      </div>
                      <button disabled={uploading} className="w-full py-2 bg-ef-green text-black font-bold rounded text-sm disabled:opacity-50">
                        {uploading ? 'Salvando...' : 'Cadastrar'}
                      </button>
                    </form>
                  </div>
                )}

                <div className="bg-ef-card p-5 rounded-xl border border-gray-800">
                  <h4 className="font-bold mb-4">Participantes ({times.length}/{campeonatoAtivo.qtd_times})</h4>
                  <div className="space-y-2">
                    {times.length === 0 ? <p className="text-gray-500 text-sm">Nenhum time ainda.</p> : times.map(t => (
                      <div key={t.id} className="flex justify-between items-center p-2 bg-ef-dark rounded group">
                        <div className="flex items-center space-x-3">
                          {t.escudo_url ? <img src={t.escudo_url} alt="Escudo" className="w-6 h-6 rounded-full object-cover" /> : <div className="w-6 h-6 rounded-full bg-gray-700 text-[10px] flex items-center justify-center">🛡️</div>}
                          <span className="text-sm font-bold">{t.nome}</span>
                        </div>
                        {/* Só o Dono pode remover times */}
                        {isOwner && partidas.length === 0 && (
                          <button onClick={() => removerTime(t.id)} className="text-red-500 opacity-0 group-hover:opacity-100 transition text-xs">Excluir</button>
                        )}
                      </div>
                    ))}
                  </div>
                </div>
              </div>

              {/* CONTEÚDO PRINCIPAL: JOGOS E CLASSIFICAÇÃO */}
              <div className="lg:col-span-3">
                <div className="flex space-x-2 mb-6 bg-ef-card p-1 rounded-full w-max border border-gray-800">
                  <button onClick={() => setActiveTab('confrontos')} className={`px-6 py-2 rounded-full font-bold text-sm transition ${activeTab === 'confrontos' ? 'bg-ef-green text-black' : 'text-gray-400 hover:text-white'}`}>CONFRONTOS</button>
                  <button onClick={() => setActiveTab('tabela')} className={`px-6 py-2 rounded-full font-bold text-sm transition ${activeTab === 'tabela' ? 'bg-ef-green text-black' : 'text-gray-400 hover:text-white'}`}>CLASSIFICAÇÃO</button>
                </div>

                {activeTab === 'confrontos' && (
                  <div className="space-y-8">
                    {partidas.length === 0 ? <p className="text-gray-500 p-8 border border-dashed border-gray-800 rounded-xl text-center">Tabela ainda não foi gerada pelo administrador.</p> : (
                      [...new Set(partidas.map(p => p.rodada))].map(r => (
                        <div key={r}>
                          <h5 className="text-gray-400 font-bold mb-4 uppercase text-sm border-b border-gray-800 pb-2">Rodada {r}</h5>
                          <div className="space-y-2">
                            {partidas.filter(p => p.rodada === r).map(p => (
                              <div key={p.id} className="flex items-center bg-ef-card p-3 rounded-xl border border-gray-800">
                                
                                <div className="flex-1 flex justify-end items-center space-x-3 pr-2">
                                  <span className="font-bold text-sm md:text-base hidden sm:block">{p.time_casa?.nome}</span>
                                  {p.time_casa?.escudo_url ? <img src={p.time_casa.escudo_url} alt="Casa" className="w-8 h-8 rounded-full object-cover" /> : <div className="w-8 h-8 rounded-full bg-gray-700"></div>}
                                </div>

                                <div className="mx-2 flex space-x-1 bg-black px-3 py-2 rounded-lg border border-gray-800">
                                  {/* Só o dono pode digitar no input. Visitantes veem como ReadOnly */}
                                  <input type="number" readOnly={!isOwner} defaultValue={p.gols_casa} onBlur={e => isOwner && atualizarPlacar(p.id, parseInt(e.target.value), p.gols_fora)} className="w-6 bg-transparent text-center font-bold text-ef-green focus:outline-none" />
                                  <span className="text-gray-600 font-bold text-sm pt-1">X</span>
                                  <input type="number" readOnly={!isOwner} defaultValue={p.gols_fora} onBlur={e => isOwner && atualizarPlacar(p.id, p.gols_casa, parseInt(e.target.value))} className="w-6 bg-transparent text-center font-bold text-ef-green focus:outline-none" />
                                </div>

                                <div className="flex-1 flex justify-start items-center space-x-3 pl-2">
                                  {p.time_fora?.escudo_url ? <img src={p.time_fora.escudo_url} alt="Fora" className="w-8 h-8 rounded-full object-cover" /> : <div className="w-8 h-8 rounded-full bg-gray-700"></div>}
                                  <span className="font-bold text-sm md:text-base hidden sm:block">{p.time_fora?.nome}</span>
                                </div>

                              </div>
                            ))}
                          </div>
                        </div>
                      ))
                    )}
                  </div>
                )}

                {activeTab === 'tabela' && (
                  <div className="bg-ef-card rounded-xl border border-gray-800 overflow-x-auto">
                    <table className="w-full text-left min-w-[600px]">
                      <thead className="bg-gray-900 text-gray-500 text-xs uppercase">
                        <tr>
                          <th className="p-4 rounded-tl-xl">#</th>
                          <th className="p-4">Clube</th>
                          <th className="p-4 text-center">PTS</th>
                          <th className="p-4 text-center">J</th>
                          <th className="p-4 text-center">V</th>
                          <th className="p-4 text-center">E</th>
                          <th className="p-4 text-center">D</th>
                          <th className="p-4 text-center rounded-tr-xl">SG</th>
                        </tr>
                      </thead>
                      <tbody>
                        {calcularClassificacao().map((t, i) => (
                          <tr key={t.id} className="border-b border-gray-800 hover:bg-gray-800 transition">
                            <td className="p-4 font-bold text-gray-400">{i + 1}</td>
                            <td className="p-4 font-bold flex items-center space-x-3">
                               {t.escudo_url ? <img src={t.escudo_url} alt="Escudo" className="w-8 h-8 rounded-full object-cover" /> : <div className="w-8 h-8 rounded-full bg-gray-700"></div>}
                               <span className="text-white">{t.nome}</span>
                            </td>
                            <td className="p-4 text-center font-black text-ef-green text-lg">{t.p}</td>
                            <td className="p-4 text-center text-gray-400">{t.j}</td>
                            <td className="p-4 text-center text-white">{t.v}</td>
                            <td className="p-4 text-center text-white">{t.e}</td>
                            <td className="p-4 text-center text-white">{t.d}</td>
                            <td className="p-4 text-center font-bold text-gray-300">{t.sg}</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
